def findAnagrams(self, s: str, p: str) -> list[int]:
    m, n = len(p), len(s)
    if n < m:
        return []
    need = Counter(p)
    win = Counter(s[:m])
    ans = [0] if win == need else []
    for r in range(m, n):
        win[s[r]] += 1
        win[s[r - m]] -= 1
        if win[s[r - m]] == 0:
            del win[s[r - m]]
        if win == need:
            ans.append(r - m + 1)
    return ans
